package com.hospital.management.controller.schedule;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DoctorScheduleServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/schedules/view")public class DoctorScheduleViewServlet extends HttpServlet{private final DoctorScheduleService service;public DoctorScheduleViewServlet(){this(new DoctorScheduleServiceImpl());}public DoctorScheduleViewServlet(DoctorScheduleService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=ScheduleRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}DoctorSchedule x=service.getSchedule(id).orElse(null);if(x==null){r.sendError(404);return;}if(!service.canAccess(x,ScheduleRequest.user(q))){r.sendError(403);return;}q.setAttribute("schedule",x);q.getRequestDispatcher("/WEB-INF/views/schedules/view.jsp").forward(q,r);}}
